        fz_stroke_state sst;
        get_stroke_state(ctx, st, &sst);
        fz_stroke_path(ctx, dc->dev, get_path(ctx,dc), &sst, ctm,
                       device_cs(ctx), st->gs.colors.line, st->gs.stroke_alpha, color_params);
